import React from 'react';
import { AppBar, Toolbar, Typography, Container } from '@material-ui/core';

const styles = {
    appBar: {
        backgroundColor: '#3bd671', // Замініть на ваший колір фону
        marginTop: 'auto',
    },
    toolbar: {
        justifyContent: 'center',
    },
    footerText: {
        color: 'white',
    },
};

function Footer() {
    return (
        <AppBar style={styles.appBar}>
            <Container>
                <Toolbar style={styles.toolbar}>
                    <Typography variant="body2" style={styles.footerText}>
                        &copy; {new Date().getFullYear()} Ваше ім'я або назва сайту. Усі права захищено.
                    </Typography>
                </Toolbar>
            </Container>
        </AppBar>
    );
}

export default Footer;
